  "lessonText": "Test your understanding of body temperature regulation.",
  "data": {
    "questions": [
      {
        "question": "What is the normal body temperature range for a healthy adult?",
        "options": ["96.8°F to 100.4°F", "98°F to 102°F", "95°F to 99°F", "97°F to 101°F"],
        "correctAnswer": 0,
        "explanation": "The normal body temperature range is typically between 96.8°F and 100.4°F."
      },
      {
        "question": "Which part of the brain regulates body temperature?",
        "options": ["Cerebellum", "Hypothalamus", "Medulla Oblongata", "Cerebrum"],
        "correctAnswer": 1,
        "explanation": "The hypothalamus is the part of the brain responsible for regulating body temperature."
      },
      {
        "question": "What is the term for a body temperature above the normal range?",
        "options": ["Hypothermia", "Hyperthermia", "Fever", "Chills"],
        "correctAnswer": 2,
        "explanation": "A body temperature above the normal range is referred to as a fever."
      },
      {
        "question": "Which of the following can cause a fever?",
        "options": ["Infection", "Dehydration", "Overheating", "All of the above"],
        "correctAnswer": 3,
        "explanation": "Infection, dehydration, and overheating can all lead to a fever."
      }
    ]
  }
}
